    public static void doZip(String encoding, String zipSource, String pDestination) throws Exception {// zipDirectoryPath:需要壓縮的文件夾名
        File zipDir;
        ZipArchiveOutputStream aos = null;
        zipDir = new File(zipSource);
        String zipFileName = zipDir.getName() + ".zip";// 壓縮後生成的zip文件名
        String zipDirectory = zipSource + zipFileName;
        if (null != pDestination || "" != pDestination) {
            zipDirectory = pDestination;
        }
        System.out.println("檔案名稱zipDirectory:" + zipDirectory);
        try {
            // 產出檔位置
            FileOutputStream fos = new FileOutputStream(zipDirectory);
            aos = new ZipArchiveOutputStream(fos);
            aos.setEncoding(encoding);
            compress(zipDir, aos, "");
        } catch (IOException ioe) {
            throw ioe;
        } finally {
            try {
                if (null != aos) {
                    aos.close();
                }
            } catch (IOException ioe) {
                ioe.printStackTrace();
            }
        }
    }
    
    private static void compress(File file, ZipArchiveOutputStream out, String basedir) throws Exception {
        /* 判斷是目錄還是文件 */
        if (file.isDirectory()) {
            compressDirectory(file, out, basedir);
        } else {
            compressFile(file, out, basedir);
        }
    }

    /** 壓縮一個目錄 */
    private static void compressDirectory(File dir, ZipArchiveOutputStream out, String basedir) throws Exception {
        if (!dir.exists()) {
            return;
        }
        File[] files = dir.listFiles();
        for (int i = 0; i < files.length; i++) {
            compress(files[i], out, basedir + dir.getName() + "/");
        }
    }

    /** 壓縮一個文件 */
    private static void compressFile(File file, ZipArchiveOutputStream out, String basedir) throws Exception {
        if (!file.exists()) {
            return;
        }
        BufferedInputStream bis = null;
        try {
//            System.out.println("ready compression of file for：" + file.getName());
            bis = new BufferedInputStream(new FileInputStream(file));
            ZipArchiveEntry entry = new ZipArchiveEntry(basedir + file.getName());
            out.putArchiveEntry(entry);
            IOUtils.copy(bis, out);
            out.closeArchiveEntry();
        } catch (IOException ioe) {
            ioe.printStackTrace();
        } finally {
            try {
                if (null != bis) {
                    bis.close();
                }
            } catch (IOException ioe) {
                ioe.printStackTrace();
            }
        }
    }

    /** 壓縮一個目錄，不包含自己那層 */
    private static void compressDirectoryFirst(File dir, ZipArchiveOutputStream out, String basedir) throws Exception {
        if (!dir.exists()) {
            return;
        }
        File[] files = dir.listFiles();
        for (int i = 0; i < files.length; i++) {
            if (files[i].getName().indexOf(".zip") == -1) {
//                System.out.println("ready compression of file for：" + files[i].getName());
                compress(files[i], out, "");
        }
    }
 }
    
 public static void deleteDirectory(File path) {
    if (path == null)
        return;
    if (path.exists()) {
        for(File f : path.listFiles()){
            if(f.isDirectory()){
                deleteDirectory(f);
                f.delete();
            } else {
                f.delete();
            }
        }
        path.delete();
    }
}
/** 刪除一個目錄，不包含自己那層 */
public static void deleteDirectoryFiles(File path) {
    if (path == null)
        return;
    if (path.exists()) {
        for(File f : path.listFiles()){
            if(f.isDirectory()){
                deleteDirectory(f);
                f.delete();
            } else {
                f.delete();
            }
        }
        //path.delete();
    }
} 
   



