    private String getIntouchID(String storeName) {
        APIQuery query = new APIQuery(AP_NAME, "/1_pg", 27);
        query.setFiltersStringV2(new String[]{"1000057|" + NUIFilter.OPERAND_EQ+"|"+storeName});
        Iterator<APIEntry> it = query.getAPIResults().iterator(query.getForm());
        if (it.hasNext()) {
            return it.next().getFieldValue("Intouch ID");
        }
        return null;
    }

